<div class="card mb-3">
    <div class="card-header"><h6 class="mb-0">Active Sessions</h6></div>
    <div class="card-body">
        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-striped mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }

        @if (_sessionToRevoke is not null)
        {
            <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5)">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking..." : "Revoke")
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _sessionToRevoke = null;
        _revoking = false;
    }
}

