{"file_text": "@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card">
    <div class="card-header"><h5 class="mb-0">Security Settings</h5></div>
    <div class="card-body">
        @if (_loading)
        {
            <p>Loading security settings...</p>
        }
        else
        {
            <ChangePasswordPanel SettingsService="SettingsService" />

            <div class="card mb-3">
                <div class="card-header"><h6 class="mb-0">Two-Factor Authentication</h6></div>
                <div class="card-body">
                    <div class="d-flex align-items-center gap-3">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="twoFactor"
                                   checked="@_twoFactorEnabled" @onchange="ToggleTwoFactor" />
                            <label class="form-check-label" for="twoFactor">Enable Two-Factor Authentication</label>
                        </div>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    @if (_lastPasswordChange.HasValue)
                    {
                        <p class="text-muted small mt-2 mb-0">
                            Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </p>
