        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("Profile", "Profile", "👤"),
        new("Notifications", "Notifications", "🔔"),
        new("Security", "Security", "🔒"),
        new("Appearance", "Appearance", "🎨")
    ];
}

@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card">
    <div class="card-header"><h5 class="mb-0">Profile Settings</h5></div>
    <div class="card-body">
        @if (_loading)
        {
            <p>Loading profile...</p>
        }
        else
        {
            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label">Display Name</label>
                        <input type="text" class="form-control" @bind="_displayName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_email" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                    </div>
                </div>
                <div class="col-md-4 text-center">
                    <div class="mb-3">
                        <label class="form-label">Avatar Preview</label>
                        <div class="border rounded p-2 mb-2">
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:120px;height:120px;object-fit:cover;" />
                        </div>
                        <small class="text-muted text-break">@_avatarUrl</small>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Avatar URL</label>
                        <input type="text" class="form-control" @bind="_avatarUrl" />
                    </div>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-2" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public ISettingsService SettingsService { get; set; } = default!;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Error saving profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _message = null;
        }
    }
}

