@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h6 class="mb-0">Change Password</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="() => _expanded = !_expanded">
            @(_expanded ? "▲ Collapse" : "▼ Expand")
        </button>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_passwordMessage))
            {
                <div class="alert @(_passwordError ? "alert-danger" : "alert-success") mb-3">@_passwordMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_updatingPassword">
                @(_updatingPassword ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordMessage;
    private bool _passwordError;
    private bool _updatingPassword;

    private async Task UpdatePasswordAsync()
    {
        _passwordMessage = null;
        _passwordError = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordMessage = "Current password is required.";
            _passwordError = true;
            return;
        }

        if (_newPassword.Length < 6)
        {
            _passwordMessage = "New password must be at least 6 characters.";
            _passwordError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordError = true;
            return;
        }

        _updatingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Error: {ex.Message}";
            _passwordError = true;
        }
        finally
        {
            _updatingPassword = false;
        }
    }
}

