@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card mb-3">
    <div class="card-header"><h6 class="mb-0">Active Sessions</h6></div>
    <div class="card-body">
        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-striped mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }

        @if (_sessionToRevoke is not null)
        {
            <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5)">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking..." : "Revoke")
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _sessionToRevoke = null;
        _revoking = false;
    }
}

@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card">
    <div class="card-header"><h5 class="mb-0">Security Settings</h5></div>
    <div class="card-body">
        @if (_loading)
        {
            <p>Loading security settings...</p>
        }
        else
        {
            <ChangePasswordPanel SettingsService="SettingsService" />

            <div class="card mb-3">
                <div class="card-header"><h6 class="mb-0">Two-Factor Authentication</h6></div>
                <div class="card-body">
                    <div class="d-flex align-items-center gap-3">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="twoFactor"
                                   checked="@_twoFactorEnabled" @onchange="ToggleTwoFactor" />
                            <label class="form-check-label" for="twoFactor">Enable Two-Factor Authentication</label>
                        </div>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    @if (_lastPasswordChange.HasValue)
                    {
                        <p class="text-muted small mt-2 mb-0">
                            Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </p>
                    }
                </div>
            </div>

            <ActiveSessionsTable Sessions="_sessions" CurrentSessionId="sess-1" OnRevoke="RevokeSessionAsync" />
        }
    </div>
</div>

@code {
    [Parameter] public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void ToggleTwoFactor(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)(e.Value ?? false);
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _sessions = settings.Sessions;
    }
}

