@using sv_1c8249ffebe7454986b32c448d44bc14.Services

<div class="card">
    <div class="card-header"><h5 class="mb-0">Appearance Settings</h5></div>
    <div class="card-body">
        @if (_loading)
        {
            <p>Loading appearance settings...</p>
        }
        else
        {
            <div class="row">
                <div class="col-md-6">
                    <div class="mb-4">
                        <h6>Theme</h6>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>

                    <div class="mb-4">
                        <h6>Font Size</h6>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>

                    <div class="mb-4">
                        <h6>Language</h6>
                        <select class="form-select" @bind="_language">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                        </select>
                    </div>

                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>

                <div class="col-md-6">
                    <h6>Live Preview</h6>
                    <div class="border rounded p-3 @PreviewClasses" style="@PreviewStyle min-height:200px;">
                        <h6 style="@PreviewFontStyle">Sample Heading</h6>
                        <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                            This is how your content will look with the selected settings.
                        </p>
                        <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                            Theme: <strong>@_theme</strong> · Font: <strong>@_fontSize</strong> · Language: <strong>@_language</strong>
                        </p>
                        <button class="btn @(_theme == "Dark" ? "btn-light" : "btn-dark") btn-sm" disabled>Sample Button</button>
                    </div>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <button class="btn btn-primary mt-3" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving..." : "Save")
            </button>
        }
    </div>
</div>

@code {
    [Parameter] public ISettingsService SettingsService { get; set; } = default!;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewClasses => _theme == "Dark" ? "text-white" : "";
    private string PreviewStyle => _theme == "Dark"
        ? "background-color:#1e1e1e;color:#e0e0e0;"
        : "background-color:#ffffff;color:#212529;";

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.25rem;",
        _ => "font-size:1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance saved!";
        _saving = false;
    }
}

